import json
import requests
import re
import time
import sys

def search_github(query):
    url = f'https://api.github.com/search/repositories?q={requests.utils.quote(query)}'
    try:
        resp = requests.get(url, timeout=10)
        if resp.status_code == 200:
            data = resp.json()
            return data.get('items', [])
        else:
            print(f'Error: {resp.status_code}', file=sys.stderr)
            return []
    except Exception as e:
        print(f'Exception: {e}', file=sys.stderr)
        return []

def extract_id_title(line):
    # line like '1. STAIR: Improving Safety Alignment with Introspective Reasoning'
    match = re.match(r'(\d+)\.\s+(.+)', line.strip())
    if match:
        pid = match.group(1)
        title = match.group(2)
        return pid, title
    return None, None

def get_acronym(title):
    # first word before colon
    colon = title.find(':')
    if colon != -1:
        return title[:colon].strip()
    # else first word
    words = title.split()
    if words:
        return words[0]
    return ''

def is_likely_official(repo, acronym):
    # repo is dict from GitHub API
    full_name = repo.get('full_name', '').lower()
    description = repo.get('description', '').lower()
    # check if acronym appears in repo name
    if acronym and acronym.lower() in full_name:
        return True
    # check for known orgs
    orgs = ['facebookresearch', 'google-research', 'microsoft', 'deepmind', 'openai', 'meta-llama', 'kaiminghe', 'facebook', 'google', 'mit', 'stanford', 'cmu', 'ucla', 'oxford', 'berkeley']
    for org in orgs:
        if full_name.startswith(org + '/'):
            return True
    # check for 'official' in description
    if 'official' in description:
        return True
    return False

def find_official_repo(title):
    queries = [
        title,
        f'{title} official code',
        f'{title} github',
        f'{title} implementation',
    ]
    acronym = get_acronym(title)
    if acronym:
        queries.append(acronym)
        queries.append(f'{acronym} github')
    all_items = []
    for q in queries:
        items = search_github(q)
        all_items.extend(items)
        time.sleep(1)  # be nice to API
    # deduplicate by full_name
    seen = set()
    unique = []
    for item in all_items:
        name = item['full_name']
        if name not in seen:
            seen.add(name)
            unique.append(item)
    # score each repo
    scored = []
    for repo in unique:
        score = repo.get('stargazers_count', 0)
        if is_likely_official(repo, acronym):
            score += 10000
        scored.append((score, repo))
    scored.sort(key=lambda x: x[0], reverse=True)
    if scored:
        return scored[0][1]['html_url']
    return None

def main():
    with open('/app/paper.txt', 'r') as f:
        lines = f.readlines()
    results = []
    for line in lines:
        line = line.strip()
        if not line:
            continue
        pid, title = extract_id_title(line)
        if not pid:
            continue
        print(f'Processing paper {pid}: {title}', file=sys.stderr)
        url = find_official_repo(title)
        if url is None:
            url = ''
        results.append({
            'paper_id': pid,
            'official_code_url': url
        })
        time.sleep(2)
    with open('/app/result.jsonl', 'w') as out:
        for res in results:
            out.write(json.dumps(res) + '\n')
    print('Done', file=sys.stderr)

if __name__ == '__main__':
    main()
EOF
